import{_ as t,o,c as a,a2 as r}from"./chunks/framework.Dc_BP1_D.js";const p=JSON.parse('{"title":"Memory Management","description":"","frontmatter":{},"headers":[],"relativePath":"agent-data-plane/memory.md","filePath":"agent-data-plane/memory.md","lastUpdated":1780607219000}'),i={name:"agent-data-plane/memory.md"};function d(s,e,n,c,m,l){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="memory-management" tabindex="-1">Memory Management <a class="header-anchor" href="#memory-management" aria-label="Permalink to &quot;Memory Management&quot;">â€‹</a></h1><p>ADP takes a different approach to memory management than the Core Agent, which relies on Go&#39;s garbage collector to reclaim memory and uses runtime GC tuning as backpressure. ADP instead uses explicit, static memory accounting and a process-level limit.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">â€‹</a></h2><table tabindex="0"><thead><tr><th>Config Key</th><th>Description</th></tr></thead><tbody><tr><td><code>memory_limit</code></td><td>Process memory limit (bytes, or SI string, for example <code>512MB</code>)</td></tr><tr><td><code>memory_slop_factor</code></td><td>Fraction of <code>memory_limit</code> held back as headroom</td></tr><tr><td><code>memory_mode</code></td><td>Bounds validation and global limiter behavior</td></tr><tr><td><code>enable_global_limiter</code></td><td>Toggle dynamic RSS-based backpressure (default: <code>true</code>)</td></tr></tbody></table><h3 id="memory-mode" tabindex="-1"><code>memory_mode</code> <a class="header-anchor" href="#memory-mode" aria-label="Permalink to &quot;`memory_mode`&quot;">â€‹</a></h3><table tabindex="0"><thead><tr><th>Value</th><th>Bounds validation failure</th><th>Global limiter active?</th></tr></thead><tbody><tr><td><code>disabled</code></td><td>Skipped (default)</td><td>No</td></tr><tr><td><code>permissive</code></td><td>Non-fatal (logged)</td><td>Yes, if <code>memory_limit</code> is set</td></tr><tr><td><code>strict</code></td><td>Fatal (ADP won&#39;t start)</td><td>Yes, if <code>memory_limit</code> is set</td></tr></tbody></table><h3 id="memory-slop-factor" tabindex="-1"><code>memory_slop_factor</code> <a class="header-anchor" href="#memory-slop-factor" aria-label="Permalink to &quot;`memory_slop_factor`&quot;">â€‹</a></h3><p><code>memory_slop_factor</code> is applied as a reduction to <code>memory_limit</code> before bounds validation. A factor of <code>0.25</code> withholds 25 % of the limit. For example, a 100 MB limit becomes an effective 75 MB budget. This accounts for allocations that ADP&#39;s static accounting doesn&#39;t track.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">â€‹</a></h2><p>ADP enforces memory bounds through three complementary mechanisms:</p><ul><li><strong>Static bounds</strong>: components declare their memory footprint at startup via <code>MemoryBounds</code>. ADP validates that declared bounds fit within the effective limit (<code>memory_limit</code> Ã— (1 âˆ’ <code>memory_slop_factor</code>)). Under <code>strict</code> mode, ADP refuses to start if bounds are exceeded, preventing over-commitment before any traffic arrives. This covers string interning caches (context strings, tag strings, OTLP strings), aggregation state, and other bounded allocations.</li><li><strong>Dynamic limiting</strong>: a <code>MemoryLimiter</code> polls the process RSS every 250 ms. When usage exceeds 95 % of the effective limit it applies proportional async backpressure (1â€“25 ms) to ingestion tasks. Disable with <code>enable_global_limiter: false</code>.</li><li><strong>Structural backpressure</strong>: bounded channels between components provide back-pressure independently of memory monitoring.</li></ul><h2 id="comparison-with-core-agent" tabindex="-1">Comparison with Core Agent <a class="header-anchor" href="#comparison-with-core-agent" aria-label="Permalink to &quot;Comparison with Core Agent&quot;">â€‹</a></h2><p>The Core Agent exposes <code>dogstatsd_mem_based_rate_limiter.*</code> settings to apply backpressure when the Go process approaches its memory limit. Those settings work by manipulating Go&#39;s garbage collector (<code>debug.SetGCPercent</code>, <code>debug.FreeOSMemory</code>), allocating a large heap ballast to adjust GC heuristics, and blocking goroutines to slow packet ingestion. None of these mechanisms have an equivalent in Rust, and ADP does not use a Go runtime. All 11 <code>dogstatsd_mem_based_rate_limiter.*</code> keys are ignored by ADP.</p>',13)])])}const g=t(i,[["render",d]]);export{p as __pageData,g as default};
